import{c as e,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Boris Cherny 的 15 個 Claude Code 隱藏技巧 — @cgtwts","description":"","frontmatter":{"title":"Boris Cherny 的 15 個 Claude Code 隱藏技巧 — @cgtwts","author":"CG（@cgtwts）","date":"2026-04-19T00:00:00.000Z","source":"https://x.com/cgtwts/status/2046009079861219375","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-19-@cgtwts-219375.md","filePath":"research/tweets/2026-04-19-@cgtwts-219375.md","lastUpdated":1779894392000}'),s={name:"research/tweets/2026-04-19-@cgtwts-219375.md"};function d(l,t,i,n,h,c){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="boris-cherny-的-15-個-claude-code-隱藏技巧-—-cgtwts" tabindex="-1">Boris Cherny 的 15 個 Claude Code 隱藏技巧 — @cgtwts <a class="header-anchor" href="#boris-cherny-的-15-個-claude-code-隱藏技巧-—-cgtwts" aria-label="Permalink to &quot;Boris Cherny 的 15 個 Claude Code 隱藏技巧 — @cgtwts&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/cgtwts/status/2046009079861219375" target="_blank" rel="noreferrer">https://x.com/cgtwts/status/2046009079861219375</a><strong>作者</strong>：CG（@cgtwts） <strong>發布日期</strong>：2026-04-19 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：推文 <strong>統計</strong>：345 likes · 43 retweets · 803 bookmarks · 57,626 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>Claude code&#39;s creator Boris Cherny, dropped 15 hidden and underused tips from his workflow</p><p>most people still aren&#39;t doing this</p><p>here&#39;s his setup:</p><p>he runs 5 to 10 claudes in parallel, even from his phone</p><p>what makes it work:</p><blockquote><p>use the smartest model, it uses fewer tokens and ends up cheaper</p></blockquote><blockquote><p>maintain a shared claude.md, updated often so mistakes are not repeated</p></blockquote><blockquote><p>give it feedback loops by letting it run code and see results in the browser</p></blockquote><p>workflow:</p><ul><li>start with a plan</li><li>lock it in</li><li>then let it apply changes and finish.</li></ul><p>Simple yet highly efficient.</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：整理 Claude Code 創作者 Boris Cherny 的工作流程核心原則——平行執行、共享 CLAUDE.md、使用最強模型反而更省錢、給予 feedback loop。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>平行運行 5-10 個 Claude 實例（包括從手機）是 Boris 的標準工作模式</li><li>反直覺的 token 節省邏輯：用最強模型（更貴/token）反而總成本更低，因為它更少失誤、更少重試</li><li>共享且頻繁更新的 CLAUDE.md 是避免重複錯誤的關鍵機制</li><li>Feedback loop 設計：讓 Claude 跑程式碼並在瀏覽器看結果，而非單純文字交流</li><li>Plan → Lock → Apply 的三步工作流，簡單但高效</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>平行實例數：5-10 個 Claude</li><li>核心工具：CLAUDE.md（共享更新）、Plan mode（鎖定計劃後執行）</li><li>重要原則：最強模型 → 更少 token 消耗 → 更便宜</li><li>Boris Cherny：Claude Code 創作者</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>「15 個技巧」的標題但推文實際只整理了 3-4 個核心原則，內容與標題不符</li><li>這些原則在本 workspace 的 CLAUDE.md 和 <code>.claude/rules/</code> 中已有大量落地實踐</li><li>「最強模型更省錢」的論述缺乏量化依據，對複雜 agentic 任務可能成立，但簡單任務用 Haiku 仍更划算</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>4/10</td><td>提到的原則（CLAUDE.md 頻繁更新、Plan mode、feedback loop）已完全落地於本 workspace；無新增行動點</td></tr><tr><td>B. 創新性 (20%)</td><td>4/10</td><td>Boris Cherny 的直接經驗有一定權威性，但這些原則在本 workspace 文件中均已涵蓋</td></tr><tr><td>C. 證據品質 (20%)</td><td>4/10</td><td>來源是 Claude Code 創作者本人（高可信度），但細節極少，聲稱「15 個技巧」實際只說了 3-4 個</td></tr><tr><td>D. 技術深度 (15%)</td><td>3/10</td><td>每個要點都是一句話描述，無具體設定方法或範例</td></tr><tr><td>E. 泛化性 (15%)</td><td>7/10</td><td>所提原則適用於所有 Claude Code 使用者</td></tr><tr><td><strong>加權總分</strong></td><td><strong>4.25/10</strong></td><td>4×0.3 + 4×0.2 + 4×0.2 + 3×0.15 + 7×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Skip <strong>理由</strong>：所有提到的原則已完整落地於本 workspace 的規則和設定中；推文內容過於精簡，無足夠細節值得額外歸檔</p>',28)])])}const g=e(s,[["render",d]]);export{u as __pageData,g as default};
